import graphene
from graphene import ObjectType, Mutation, String, Boolean, Int, Field

# Simulated database
users_db = {
    1: {
        "id": 1,
        "username": "alice",
        "email": "alice@example.com",
        "bio": "Hello, I'm Alice",
        "role": "user",
        "is_admin": False,
        "credits": 100,
        "subscription_tier": "free",
    },
    2: {
        "id": 2,
        "username": "bob",
        "email": "bob@example.com",
        "bio": "Hello, I'm Bob",
        "role": "admin",
        "is_admin": True,
        "credits": 500,
        "subscription_tier": "premium",
    },
}

# Fields that only admins can modify
ADMIN_ONLY_FIELDS = {"role", "is_admin", "credits", "subscription_tier"}

# Fields that regular users can modify on their own profile
USER_EDITABLE_FIELDS = {"username", "email", "bio"}

# All valid fields
ALL_UPDATABLE_FIELDS = ADMIN_ONLY_FIELDS | USER_EDITABLE_FIELDS


class UserType(ObjectType):
    id = Int()
    username = String()
    email = String()
    bio = String()
    role = String()
    is_admin = Boolean()
    credits = Int()
    subscription_tier = String()


class UpdateUserProfile(Mutation):
    class Arguments:
        target_user_id = Int(description="ID of the user to update. If not provided, updates the authenticated user.")
        username = String()
        email = String()
        bio = String()
        role = String()
        is_admin = Boolean()
        credits = Int()
        subscription_tier = String()

    user = Field(UserType)
    success = Boolean()
    message = String()

    @staticmethod
    def mutate(root, info, target_user_id=None, **kwargs):
        # Step 1: Authenticate the user
        current_user = info.context.get("current_user")
        if not current_user:
            return UpdateUserProfile(user=None, success=False, message="Authentication required.")

        current_user_id = current_user["id"]
        current_user_is_admin = current_user.get("is_admin", False)

        # Step 2: Determine the target user
        if target_user_id is None:
            target_user_id = current_user_id

        target_user = users_db.get(target_user_id)
        if not target_user:
            return UpdateUserProfile(user=None, success=False, message="User not found.")

        # Step 3: Filter out None values (fields not provided in the mutation)
        provided_fields = {k: v for k, v in kwargs.items() if v is not None}

        if not provided_fields:
            return UpdateUserProfile(user=None, success=False, message="No fields provided for update.")

        # Step 4: Validate that all provided field names are recognized
        invalid_fields = set(provided_fields.keys()) - ALL_UPDATABLE_FIELDS
        if invalid_fields:
            return UpdateUserProfile(
                user=None, success=False,
                message=f"Invalid fields: {', '.join(invalid_fields)}"
            )

        # Step 5: Authorization checks
        requested_privileged_fields = set(provided_fields.keys()) & ADMIN_ONLY_FIELDS

        if target_user_id != current_user_id:
            # Modifying another user's profile requires admin privileges
            if not current_user_is_admin:
                return UpdateUserProfile(
                    user=None, success=False,
                    message="Permission denied. Only admins can modify other users' profiles."
                )

        if requested_privileged_fields:
            # Privileged fields (role, is_admin, credits, subscription_tier) require admin
            if not current_user_is_admin:
                return UpdateUserProfile(
                    user=None, success=False,
                    message=f"Permission denied. Only admins can modify: {', '.join(requested_privileged_fields)}"
                )

        # Step 6: Additional validation on field values
        if "role" in provided_fields:
            allowed_roles = {"user", "moderator", "admin"}
            if provided_fields["role"] not in allowed_roles:
                return UpdateUserProfile(
                    user=None, success=False,
                    message=f"Invalid role. Allowed roles: {', '.join(allowed_roles)}"
                )

        if "subscription_tier" in provided_fields:
            allowed_tiers = {"free", "basic", "premium", "enterprise"}
            if provided_fields["subscription_tier"] not in allowed_tiers:
                return UpdateUserProfile(
                    user=None, success=False,
                    message=f"Invalid subscription tier. Allowed: {', '.join(allowed_tiers)}"
                )

        if "credits" in provided_fields:
            if not isinstance(provided_fields["credits"], int) or provided_fields["credits"] < 0:
                return UpdateUserProfile(
                    user=None, success=False,
                    message="Credits must be a non-negative integer."
                )

        if "email" in provided_fields:
            email = provided_fields["email"]
            if not email or "@" not in email or len(email) > 254:
                return UpdateUserProfile(
                    user=None, success=False,
                    message="Invalid email address."
                )

        if "username" in provided_fields:
            username = provided_fields["username"]
            if not username or len(username) < 3 or len(username) > 30:
                return UpdateUserProfile(
                    user=None, success=False,
                    message="Username must be between 3 and 30 characters."
                )
            if not username.isalnum() and not all(c.isalnum() or c in ('_', '-') for c in username):
                return UpdateUserProfile(
                    user=None, success=False,
                    message="Username can only contain alphanumeric characters, underscores, and hyphens."
                )

        if "bio" in provided_fields:
            if len(provided_fields["bio"]) > 500:
                return UpdateUserProfile(
                    user=None, success=False,
                    message="Bio must be 500 characters or fewer."
                )

        # Step 7: Apply the updates (only allowed fields)
        for field, value in provided_fields.items():
            target_user[field] = value

        return UpdateUserProfile(
            user=UserType(**target_user),
            success=True,
            message="Profile updated successfully."
        )


class Query(ObjectType):
    me = Field(UserType)

    @staticmethod
    def resolve_me(root, info):
        current_user = info.context.get("current_user")
        if not current_user:
            return None
        user_data = users_db.get(current_user["id"])
        if user_data:
            return UserType(**user_data)
        return None


class Mutations(ObjectType):
    update_user_profile = UpdateUserProfile.Field()


schema = graphene.Schema(query=Query, mutation=Mutations)


